91,-0.01699604,0.01885444,0.02703375,-0.00785604,0.00210247,0.02297790,0.05306518,-0.02217080,0.01004352,-0.00952968,-0.00643641,0.00758756,-0.00123514,0.05054826,-0.05742504,-0.00898216,0.02134554,0.01498087,0.03477658,-0.02101102,0.02966125,0.06882995,-0.00885645,0.02836329,-0.02581539,-0.02918959,0.00242643,-0.02100211,0.00795863,0.01519489,-0.02362158,0.03902047,0.06753321,-0.00408908,0.02437128,-0.04185991,-0.01299120,0.02802710,-0.07697155,0.08138887,-0.01685122,-0.00499035]',E'Example\n\nAdd warp and Tokio to your dependencies:\n\n```toml\ntokio = { version = "1", features = ["full"] }\nwarp = { version = "0.4", features = ["server"] }\n```\n\nAnd then get started in your `main.rs`:\n\n```rust\nuse warp::Filter;\n\n#[tokio::main]\nasync fn main() {\n    // GET /hello/warp => 200 OK with body "Hello, warp!"\n    let hello = warp::path!("hello" / String)\n        .map(|name| format!("Hello, {}!", name));\n\n    warp::serve(hello)\n        .run(([127, 0, 0, 1], 3030))\n        .await;\n}\n```\n\nFor more information you can check the [docs](https://docs.rs/warp) or the [examples](https://github.com/seanmonstar/warp/tree/master/examples).\n\n[discord-badge]: https://img.shields.io/discord/500028886025895936.svg?logo=discord\n[discord-url]: https://discord.gg/RFsPjyt','{"source": "warp", "version": "0.3", "language": "rust", "title": "warp", "section_title": "README", "url": "https://github.com/seanmonstar/warp/blob/master/README.md", "topics": "warp,http,async,README", "categories": "web,rust,rest,async"}');
